script.text:

function load$CheckingReport$(g) {
  g._$k1 = [];
  g._$k2 = [];
  g._$ks = [];
  g._$i1 = g._getColumnOrder('stt_rec');
  g._$i2 = g._getColumnOrder('so_hdld');
  g._$t = g._getColumnOrder('tag');
  g._$f1 = 'key1';
  g._$f2 = 'key2';
  g.add_commandEvent(on$GridReport$ExecuteCommand);
}
function dispose$CheckingReport$(g) {
  g._$k1 = g._$k2 = g._$ks = g._$i1 = g._$i2 = g._$t = g._$f1 = g._$f2 = null;
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
}
function scatter$GridReport$(g) {
  fill$Grid(g, true);
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	}
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'Print':
      e.type.cancelEvent = !isCheck$Grid(g);
      init$ExportKey(g);
      break;
    default:
      break;
  }
}

      &JavascriptReportInit;

function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._$ks.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$ks.length == 0) return;
  for (var r = 1; r <= g._rowCount; r++) {
    var k1 = row$Key(g, r), k2 = row$Key(g, r, 1), i = Array.indexOf(g._$ks, k1 + String.fromCharCode(255) + k2);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function init$ExportKey(g) {
  var k1 = g._$k1.join(','), k2 = g._$k2.join(','), v = g._filterMemvars, m1 = v[$func.findMemvarIndex(g._$f1, v)], m2 = v[$func.findMemvarIndex(g._$f2, v)];
  m1.NewValue = m1.Compressed ? $func.compress(k1) : k1;
  m2.NewValue = m2.Compressed ? $func.compress(k2) : k2;
}
function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    if (!g._getItem(r, g._$t).disabled) {
      var i = reset$Grid(g, r);
      g._setItemValue(r, g._$t, (i == -1));
    }
  }

  if (g._rowCount <= 0) return;
  else {
	  g._activeRow = g._rowCount;
	  g._activeColumn = g._$t;
	  g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	  g._focusWhenTabChanged();
  }
}
function onChange$SelectedValue(o) {
  var a = o.id.split('_inputCell_'), g = o.grid;
  if (!g) g = $find(a[0]);
  var r = $func.getLocationCell(o)[0];
  reset$Grid(g, r);
  g._activeRow = a[1].split('.')[0];
  g._activeColumn = a[1].split('.')[1];
  g._activeCell = g._getItem(g._activeRow, g._activeColumn);
}
function reset$Grid(g, r) {
  var k1 = row$Key(g, r), k2 = row$Key(g, r, 1), i = Array.indexOf(g._$ks, k1 + String.fromCharCode(255) + k2);
  if (i == -1) {
    Array.add(g._$k1, k1);
    Array.add(g._$k2, k2);
    Array.add(g._$ks, k1 + String.fromCharCode(255) + k2); 
  }  
  else {
    Array.removeAt(g._$k1, i);
    Array.removeAt(g._$k2, i);
    Array.removeAt(g._$ks, i); 
  }
  return i;
}
function row$Key(g, r, force) {
  var c = g._getItemValue(r, force ? g._$i2 : g._$i1);
  if (force) c = $func.padRight(c, g._$l);
  return c;
}
